// Some portions generated by Codex
package org.eclipse.rdf4j.query.algebra.evaluation.optimizer.cascades;

import static org.junit.jupiter.api.Assertions.assertEquals;
import static org.junit.jupiter.api.Assertions.assertFalse;
import static org.junit.jupiter.api.Assertions.assertTrue;

import java.util.Set;

import org.junit.jupiter.api.Test;

class CascadesSearchStateStatusTest {

	@Test
	void exactRuleLimitStopsBeforeOvershootAndReportsResourceLimit() {
		CascadesPlanner.SearchState state = new CascadesPlanner.SearchState(
				OptimizationGoal.SearchMode.EXACT, limits(1L));
		OptimizationGoal goal = goal(OptimizationGoal.SearchMode.EXACT, Long.MAX_VALUE);

		assertTrue(state.consumeMajor("first"));
		assertFalse(state.consumeMajor("denied"));
		assertFalse(state.consumeMajor("still-denied"));
		assertTrue(state.shouldStop(goal));

		OptimizationSearchStatus status = state.searchStatus(null);
		assertEquals(OptimizationCompleteness.RESOURCE_LIMIT_EXCEEDED, status.completeness());
		assertEquals(Set.of(OptimizationLimitCause.RULE_WORK), status.limitCauses());
		assertEquals(1L, status.counters().ruleWork(), "denied work must not overshoot the exact counter");
	}

	@Test
	void autoRuleLimitDoesNotStopIndependentSearchLanes() {
		CascadesPlanner.SearchState state = new CascadesPlanner.SearchState(
				OptimizationGoal.SearchMode.AUTO, limits(1L));
		OptimizationGoal expiredGoal = goal(OptimizationGoal.SearchMode.AUTO, 1L);

		assertFalse(state.shouldStop(expiredGoal), "AUTO has deterministic work limits, not a wall-clock deadline");
		assertTrue(state.consumeMajor("first"));
		assertFalse(state.shouldStop(expiredGoal), "an expired deadline must remain irrelevant to AUTO");
		assertFalse(state.consumeMajor("denied"));
		assertFalse(state.shouldStop(expiredGoal),
				"Exhausting Cascades rule work must not suppress already-admitted join and cost work with independent limits");

		OptimizationSearchStatus status = state.searchStatus(null);
		assertEquals(OptimizationCompleteness.BUDGET_EXHAUSTED, status.completeness());
		assertEquals(Set.of(OptimizationLimitCause.RULE_WORK), status.limitCauses());
		assertEquals(1L, status.counters().ruleWork());
	}

	@Test
	void deadlineStopsOnlyBudgetedAndShadowBudgetedSearch() {
		for (OptimizationGoal.SearchMode mode : new OptimizationGoal.SearchMode[] {
				OptimizationGoal.SearchMode.AUTO,
				OptimizationGoal.SearchMode.EXACT,
				OptimizationGoal.SearchMode.SHADOW }) {
			CascadesPlanner.SearchState state = new CascadesPlanner.SearchState(mode, limits(10L));

			assertFalse(state.shouldStop(goal(mode, 1L)), mode + " must ignore wall-clock deadlines");
			assertFalse(state.searchStatus(null).limitCauses().contains(OptimizationLimitCause.DEADLINE));
		}

		for (OptimizationGoal.SearchMode mode : new OptimizationGoal.SearchMode[] {
				OptimizationGoal.SearchMode.BUDGETED,
				OptimizationGoal.SearchMode.SHADOW_BUDGETED }) {
			CascadesPlanner.SearchState state = new CascadesPlanner.SearchState(mode, limits(10L));

			assertTrue(state.shouldStop(goal(mode, 1L)), mode + " must honor its configured deadline");
			OptimizationSearchStatus status = state.searchStatus(null);
			assertEquals(OptimizationCompleteness.DEADLINE_EXPIRED, status.completeness());
			assertEquals(Set.of(OptimizationLimitCause.DEADLINE), status.limitCauses());
		}
	}

	private static OptimizationGoal goal(OptimizationGoal.SearchMode mode, long deadlineNanos) {
		return new OptimizationGoal(PhysicalProperties.ANY, OptimizationGoal.BAG_SEMANTICS,
				OptimizationGoal.CostPolicy.EXACT, CostVector.INFINITE, Set.of(), mode, deadlineNanos, 10);
	}

	private static SearchLimits limits(long ruleWork) {
		return new SearchLimits(ruleWork, Long.MAX_VALUE, Long.MAX_VALUE, Long.MAX_VALUE, Long.MAX_VALUE,
				Long.MAX_VALUE, Long.MAX_VALUE);
	}
}
